import tkinter as tk
from tkinter import filedialog
import requests

class PaperSummarizer:
    def __init__(self, root):
        self.root = root
        self.root.title("Paper Summarizer")
        self.paper_path = None

        self.input_frame = tk.Frame(self.root)
        self.input_frame.pack()

        self.paper_button = tk.Button(self.input_frame, text="Select Paper", command=self.select_paper)
        self.paper_button.pack(side=tk.LEFT)

        self.summarize_button = tk.Button(self.input_frame, text="Generate Summary", command=self.generate_summary)
        self.summarize_button.pack(side=tk.LEFT)

        self.question_label = tk.Label(self.root, text="Enter question about the paper:")
        self.question_label.pack()

        self.question_entry = tk.Entry(self.root, width=50)
        self.question_entry.pack()

        self.answer_label = tk.Label(self.root, text="")
        self.answer_label.pack()

        self.summary_label = tk.Label(self.root, text="")
        self.summary_label.pack()

    def select_paper(self):
        self.paper_path = filedialog.askopenfilename(title="Select Paper", filetypes=[("Text Files", "*.txt")])
        if self.paper_path:
            with open(self.paper_path, 'r') as file:
                self.paper_text = file.read()

    def generate_summary(self):
        if self.paper_path:
            api_url = "https://api.claude.ai/summarize"
            headers = {"Authorization": "Bearer YOUR_CLAUDE_API_KEY"}
            data = {"text": self.paper_text}
            response = requests.post(api_url, headers=headers, json=data)
            if response.status_code == 200:
                summary = response.json()["summary"]
                self.summary_label.config(text="Summary: " + summary)
            else:
                self.summary_label.config(text="Failed to generate summary")
        else:
            self.summary_label.config(text="Please select a paper first")

    def ask_question(self):
        question = self.question_entry.get()
        if question:
            api_url = "https://api.claude.ai/answer"
            headers = {"Authorization": "Bearer YOUR_CLAUDE_API_KEY"}
            data = {"question": question, "text": self.paper_text}
            response = requests.post(api_url, headers=headers, json=data)
            if response.status_code == 200:
                answer = response.json()["answer"]
                self.answer_label.config(text="Answer: " + answer)
            else:
                self.answer_label.config(text="Failed to answer question")
        else:
            self.answer_label.config(text="Please enter a question")

        self.question_button = tk.Button(self.root, text="Ask Question", command=self.ask_question)
        self.question_button.pack()

if __name__ == "__main__":
    root = tk.Tk()
    app = PaperSummarizer(root)
    root.mainloop()

