        self.knowledge_base = {}
        self.api_key = None
        self.router = None

    def initialize_knowledge_base(self, knowledge):
        self.knowledge_base = knowledge

    def generate_api_key(self):
        import uuid
        self.api_key = str(uuid.uuid4())

    def create_router(self, routes):
        self.router = routes

    def ask_question(self, question):
        if self.router is not None:
            for route in self.router:
                if question.lower() == route['question'].lower():
                    return route['answer']
        return "Question not found in router"

    def answer_from_knowledge_base(self, question):
        for key, value in self.knowledge_base.items():
            if question.lower() == key.lower():
                return value
        return "Question not found in knowledge base"

